import{_ as t,a,b as o,c as d,d as r,e as s}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as n,o as p,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Adding a Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/dropbox.md","filePath":"en/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"en/upload/dropbox.md"};function h(b,e,u,m,f,g){return p(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="adding-a-dropbox-channel" tabindex="-1">Adding a Dropbox Channel <a class="header-anchor" href="#adding-a-dropbox-channel" aria-label="Permalink to &quot;Adding a Dropbox Channel&quot;">​</a></h1><h2 id="what-you-need-first" tabindex="-1">What You Need First <a class="header-anchor" href="#what-you-need-first" aria-label="Permalink to &quot;What You Need First&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Why You Need It</th></tr></thead><tbody><tr><td>A Dropbox account</td><td>Used to sign in and authorize the app</td></tr><tr><td>A Dropbox app</td><td>Used to generate the <code>App Key</code> and <code>App Secret</code></td></tr><tr><td>Your ImgBed domain</td><td>Used for the OAuth redirect URI</td></tr><tr><td>Available Dropbox storage</td><td>Used as the actual file storage location</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-create-a-dropbox-app" tabindex="-1">Step 1: Create a Dropbox App <a class="header-anchor" href="#step-1-create-a-dropbox-app" aria-label="Permalink to &quot;Step 1: Create a Dropbox App&quot;">​</a></h3><ol><li>Open the Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Create a new app.</li><li>For access type, choose:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Give the app a name you can recognize, such as <code>imgbed-app</code>.</li><li>Open the app details page after it is created.</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. It matches how ImgBed stores files.</td></tr><tr><td><code>Full Dropbox</code></td><td>Not recommended. ImgBed does not need full-account access.</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-add-the-redirect-uri" tabindex="-1">Step 2: Add the Redirect URI <a class="header-anchor" href="#step-2-add-the-redirect-uri" aria-label="Permalink to &quot;Step 2: Add the Redirect URI&quot;">​</a></h3><p>In the Dropbox app details page, find the OAuth or Redirect URI settings and add:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>If you use the admin panel from more than one domain, add each matching callback URL.</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-app-permissions" tabindex="-1">Step 3: Configure App Permissions <a class="header-anchor" href="#step-3-configure-app-permissions" aria-label="Permalink to &quot;Step 3: Configure App Permissions&quot;">​</a></h3><p>Open the <code>Permissions</code> tab and enable at least these scopes:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>Reads account and quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>Reads file and folder metadata for path checks</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>Creates folders and writes metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Uploads files. Missing this scope causes <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>Allows download, preview, and temporary file links</td></tr></tbody></table><p>After selecting the scopes, click <code>Submit</code> at the bottom of the page.</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>What To Do</th></tr></thead><tbody><tr><td>You changed scopes</td><td>Run the token authorization flow again and get a new <code>Refresh Token</code>.</td></tr><tr><td>You did not reauthorize</td><td>The old token will not gain the new permissions, so uploads may still fail.</td></tr></tbody></table><h3 id="step-4-copy-the-app-credentials" tabindex="-1">Step 4: Copy the App Credentials <a class="header-anchor" href="#step-4-copy-the-app-credentials" aria-label="Permalink to &quot;Step 4: Copy the App Credentials&quot;">​</a></h3><p>Save these two values from the Dropbox app page:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-fill-in-the-dropbox-channel" tabindex="-1">Step 5: Fill in the Dropbox Channel <a class="header-anchor" href="#step-5-fill-in-the-dropbox-channel" aria-label="Permalink to &quot;Step 5: Fill in the Dropbox Channel&quot;">​</a></h3><p>In Upload Settings, choose <code>Dropbox</code> and fill in:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A name you can recognize, such as <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>The Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>The Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Leave it empty for now</td></tr><tr><td>Root directory</td><td>Optional. Defaults to <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-get-the-refresh-token" tabindex="-1">Step 6: Get the Refresh Token <a class="header-anchor" href="#step-6-get-the-refresh-token" aria-label="Permalink to &quot;Step 6: Get the Refresh Token&quot;">​</a></h3><ol><li>In ImgBed, click <code>Get Token</code>.</li><li>Sign in to the Dropbox account you want to connect.</li><li>Approve the authorization prompt.</li><li>The callback page will show a <code>Refresh Token</code>.</li><li>Copy it.</li><li>Return to ImgBed and paste it into the <code>Refresh Token</code> field.</li></ol><p><img src="'+r+'" alt="Copy token" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How To Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How To Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>The Dropbox channel appears after saving.</td></tr><tr><td>Channel switch</td><td>The channel can be enabled.</td></tr><tr><td>Token saved</td><td>The detail page shows that the <code>Refresh Token</code> has been saved.</td></tr><tr><td>Upload test</td><td>A test image appears in the Dropbox app folder.</td></tr></tbody></table><p>If quota limits are enabled, click quota query. After a successful query, the channel card shows used space, total space, and the last update time.</p><p><img src="'+s+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed says the configuration is incomplete</td><td>Check that <code>App Key</code>, <code>App Secret</code>, and <code>Refresh Token</code> are all filled in.</td></tr><tr><td>Authorization succeeds but no <code>Refresh Token</code> appears</td><td>Click <code>Get Token</code> again and make sure the offline authorization flow is used.</td></tr><tr><td>Upload fails with <code>required scope &#39;files.content.write&#39;</code></td><td>Enable <code>files.content.write</code>, click <code>Submit</code>, then get a new <code>Refresh Token</code>.</td></tr><tr><td>Callback fails</td><td>Confirm the redirect URI is <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Files cannot be found</td><td>Confirm the Dropbox app was created in <code>App folder</code> mode.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Dropbox App Console</span></span>
<span class="line"><span>-&gt; Create an app</span></span>
<span class="line"><span>-&gt; Choose App folder access</span></span>
<span class="line"><span>-&gt; Add https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Optionally enable files.content.read</span></span>
<span class="line"><span>-&gt; Click Submit</span></span>
<span class="line"><span>-&gt; Copy App Key and App Secret</span></span>
<span class="line"><span>-&gt; Fill them into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const w=n(c,[["render",h]]);export{y as __pageData,w as default};
